package com.hospital.management.util;import java.util.*;/** Terminal prescription status state machine. */public final class PrescriptionStatusTransition {private PrescriptionStatusTransition(){}public static Optional<String>target(String current,String action){if(!"ACTIVE".equalsIgnoreCase(current)||action==null)return Optional.empty();return switch(action.toLowerCase(Locale.ROOT)){case"complete"->Optional.of("COMPLETED");case"cancel"->Optional.of("CANCELLED");default->Optional.empty();};}public static boolean isTerminal(String s){return"COMPLETED".equalsIgnoreCase(s)||"CANCELLED".equalsIgnoreCase(s);}}
